import{_ as a,H as i,f as n,i as e}from"./chunks/framework.BHvCMIhP.js";const k=JSON.parse('{"title":"文件系统","description":"","frontmatter":{},"headers":[],"relativePath":"osLearning/19-文件系统.md","filePath":"osLearning/19-文件系统.md","lastUpdated":1778496697000}'),l={name:"osLearning/19-文件系统.md"};function t(p,s,h,d,r,o){return i(),n("div",null,[...s[0]||(s[0]=[e(`<h1 id="文件系统" tabindex="-1">文件系统 <a class="header-anchor" href="#文件系统" aria-label="Permalink to &quot;文件系统&quot;">​</a></h1><p>文件系统解决的是一个朴素但很难的问题:把一串字节可靠地放到块设备上,断电不乱,并发不坏,查找要快,空间别浪费。你看到的是 <code>/data/a.log</code>,内核看到的是 inode、目录项、页缓存、块分配器、journal、writeback、IO 调度。这一篇讲清楚:<strong>ext4/XFS/btrfs 的取舍、一次写入如何落盘、journal 为什么存在、fsync 为什么慢、rename 为什么常用于原子更新</strong>。</p><blockquote><p>一句话先记住:<strong>文件系统 = 命名空间 + 元数据 + 数据块分配 + 崩溃一致性</strong>。普通 <code>write</code> 先写页缓存,后台再刷盘;<code>fsync</code> 才把数据推到持久层。<strong>journal 不是为了更快,是为了断电后文件系统结构不坏</strong>。数据库、日志、对象存储的很多&quot;玄学性能&quot;,本质都是文件系统写入路径和 fsync 策略。</p></blockquote><hr><h2 id="一、文件系统要解决什么" tabindex="-1">一、文件系统要解决什么 <a class="header-anchor" href="#一、文件系统要解决什么" aria-label="Permalink to &quot;一、文件系统要解决什么&quot;">​</a></h2><p>块设备只提供:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>read block 123</span></span>
<span class="line"><span>write block 456</span></span></code></pre></div><p>文件系统提供:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>/var/log/app.log</span></span>
<span class="line"><span>append 1KB</span></span>
<span class="line"><span>rename temp → final</span></span>
<span class="line"><span>chmod 0644</span></span>
<span class="line"><span>list directory</span></span></code></pre></div><p>它要维护:</p><ul><li>路径到 inode 的映射</li><li>inode 到数据块的映射</li><li>空闲空间管理</li><li>权限与时间戳</li><li>崩溃恢复</li><li>缓存与预读</li></ul><hr><h2 id="二、一次读写路径" tabindex="-1">二、一次读写路径 <a class="header-anchor" href="#二、一次读写路径" aria-label="Permalink to &quot;二、一次读写路径&quot;">​</a></h2><h3 id="_2-1-读" tabindex="-1">2.1 读 <a class="header-anchor" href="#_2-1-读" aria-label="Permalink to &quot;2.1 读&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>read(fd)</span></span>
<span class="line"><span>  → VFS</span></span>
<span class="line"><span>  → page cache 查页</span></span>
<span class="line"><span>      命中:拷贝到用户态</span></span>
<span class="line"><span>      未命中:文件系统算出块号</span></span>
<span class="line"><span>             块层发 IO</span></span>
<span class="line"><span>             磁盘/SSD 完成</span></span>
<span class="line"><span>             填 page cache</span></span>
<span class="line"><span>             拷贝到用户态</span></span></code></pre></div><p>热文件读的是内存,冷文件读的是设备。</p><h3 id="_2-2-写" tabindex="-1">2.2 写 <a class="header-anchor" href="#_2-2-写" aria-label="Permalink to &quot;2.2 写&quot;">​</a></h3><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>write(fd)</span></span>
<span class="line"><span>  → 拷贝到 page cache</span></span>
<span class="line"><span>  → 标记 dirty page</span></span>
<span class="line"><span>  → 返回</span></span>
<span class="line"><span>  → 后台 writeback 刷盘</span></span></code></pre></div><p>所以 <code>write</code> 快,但不代表安全落盘。</p><div class="language-c vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">write</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(fd, buf, n);</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">fsync</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(fd);</span></span></code></pre></div><p><code>fsync</code> 慢,因为它要等设备确认数据持久化。</p><hr><h2 id="三、崩溃一致性与-journal" tabindex="-1">三、崩溃一致性与 journal <a class="header-anchor" href="#三、崩溃一致性与-journal" aria-label="Permalink to &quot;三、崩溃一致性与 journal&quot;">​</a></h2><p>创建文件不是一次写:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>1. 分配 inode</span></span>
<span class="line"><span>2. 分配数据块</span></span>
<span class="line"><span>3. 写目录项</span></span>
<span class="line"><span>4. 更新 inode 元数据</span></span>
<span class="line"><span>5. 更新空闲块位图</span></span></code></pre></div><p>如果写到一半断电,文件系统可能出现:</p><ul><li>inode 已分配但目录没指向</li><li>目录指向不存在 inode</li><li>空闲块位图错误</li><li>文件大小和数据块不一致</li></ul><p>journal 的思路:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>先把&quot;我要做哪些元数据修改&quot;写进日志</span></span>
<span class="line"><span>日志落盘</span></span>
<span class="line"><span>再真正修改文件系统结构</span></span>
<span class="line"><span>崩溃后 replay journal</span></span></code></pre></div><h3 id="_3-1-ext4-三种模式" tabindex="-1">3.1 ext4 三种模式 <a class="header-anchor" href="#_3-1-ext4-三种模式" aria-label="Permalink to &quot;3.1 ext4 三种模式&quot;">​</a></h3><table tabindex="0"><thead><tr><th>模式</th><th>说明</th></tr></thead><tbody><tr><td><code>data=journal</code></td><td>数据和元数据都 journal,最安全最慢</td></tr><tr><td><code>data=ordered</code></td><td>默认,数据先落盘,元数据 journal</td></tr><tr><td><code>data=writeback</code></td><td>元数据 journal,数据顺序不保证</td></tr></tbody></table><p>默认 ordered 是工程折中:文件系统结构安全,数据内容仍需应用自己 fsync。</p><hr><h2 id="四、ext4-xfs-btrfs" tabindex="-1">四、ext4 / XFS / btrfs <a class="header-anchor" href="#四、ext4-xfs-btrfs" aria-label="Permalink to &quot;四、ext4 / XFS / btrfs&quot;">​</a></h2><h3 id="_4-1-ext4" tabindex="-1">4.1 ext4 <a class="header-anchor" href="#_4-1-ext4" aria-label="Permalink to &quot;4.1 ext4&quot;">​</a></h3><p>特点:</p><ul><li>通用、稳定、默认选择</li><li>journal 成熟</li><li>小文件/普通服务器表现均衡</li><li>在线扩容可以,缩容支持有限</li></ul><p>适合:大多数 Linux 业务机。</p><h3 id="_4-2-xfs" tabindex="-1">4.2 XFS <a class="header-anchor" href="#_4-2-xfs" aria-label="Permalink to &quot;4.2 XFS&quot;">​</a></h3><p>特点:</p><ul><li>擅长大文件、大目录、高并发 IO</li><li>元数据扩展性强</li><li>在线扩容成熟,不能缩容</li><li>RHEL/CentOS 常用默认</li></ul><p>适合:日志、对象存储、数据库数据盘、大容量磁盘。</p><h3 id="_4-3-btrfs" tabindex="-1">4.3 btrfs <a class="header-anchor" href="#_4-3-btrfs" aria-label="Permalink to &quot;4.3 btrfs&quot;">​</a></h3><p>特点:</p><ul><li>CoW(copy-on-write)</li><li>快照、校验、子卷、压缩</li><li>功能强,运维复杂度更高</li></ul><p>适合:需要快照/校验/子卷的场景。生产数据库是否使用要谨慎压测。</p><hr><h2 id="五、原子更新-write-temp-fsync-rename" tabindex="-1">五、原子更新:write temp + fsync + rename <a class="header-anchor" href="#五、原子更新-write-temp-fsync-rename" aria-label="Permalink to &quot;五、原子更新:write temp + fsync + rename&quot;">​</a></h2><p>配置文件更新常用套路:</p><div class="language-c vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">c</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fd </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> open</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;conf.tmp&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, O_CREAT</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">O_WRONLY</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">|</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">O_TRUNC, </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">0</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">644</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">write</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(fd, data, len);</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">fsync</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(fd);</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">close</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(fd);</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rename</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;conf.tmp&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;conf&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">fsync</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(dirfd);</span></span></code></pre></div><p>为什么:</p><ul><li><code>rename</code> 在同一文件系统内是原子的</li><li>读者要么看到旧文件,要么看到新文件</li><li>不会看到写一半的文件</li></ul><p>注意最后 <code>fsync</code> 目录,保证目录项更新落盘。</p><hr><h2 id="六、fsync-为什么慢" tabindex="-1">六、fsync 为什么慢 <a class="header-anchor" href="#六、fsync-为什么慢" aria-label="Permalink to &quot;六、fsync 为什么慢&quot;">​</a></h2><p><code>fsync</code> 要把 dirty page、相关元数据、journal 提交都推到持久层。</p><p>慢的原因:</p><ul><li>设备延迟</li><li>写放大</li><li>journal commit 等待</li><li>多个文件竞争 flush</li><li>云盘后端抖动</li><li>RAID/缓存策略</li></ul><p>数据库性能很大一部分就是在优化:</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>每事务 fsync 太慢 → group commit</span></span>
<span class="line"><span>日志顺序写 → 数据页后台刷</span></span></code></pre></div><hr><h2 id="七、目录和小文件问题" tabindex="-1">七、目录和小文件问题 <a class="header-anchor" href="#七、目录和小文件问题" aria-label="Permalink to &quot;七、目录和小文件问题&quot;">​</a></h2><p>小文件多的问题:</p><ul><li>inode 多</li><li>dentry/inode cache 压力大</li><li>元数据 IO 多</li><li>fsync 目录成本高</li><li>备份/遍历慢</li></ul><p>排查:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">df</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">find</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /path</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -type</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> f</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> wc</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -l</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">slabtop</span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;">   # 看 dentry/inode_cache</span></span></code></pre></div><p>对象存储、日志系统通常会合并小文件,或改用 LSM/数据库格式。</p><hr><h2 id="八、常见坑" tabindex="-1">八、常见坑 <a class="header-anchor" href="#八、常见坑" aria-label="Permalink to &quot;八、常见坑&quot;">​</a></h2><ol><li><strong>只 write 不 fsync</strong>:进程崩溃不丢,机器断电可能丢。</li><li><strong>fsync 文件不 fsync 目录</strong>:rename/create 后目录项可能丢。</li><li><strong>小文件海量堆积</strong>:inode 和 dentry cache 爆。</li><li><strong>把 tmpfs 当持久化</strong>:重启就没。</li><li><strong>NFS 当本地盘用</strong>:语义和延迟都不同。</li><li><strong>数据库上乱开 CoW</strong>:可能写放大严重。</li></ol><hr><h2 id="九、排查命令" tabindex="-1">九、排查命令 <a class="header-anchor" href="#九、排查命令" aria-label="Permalink to &quot;九、排查命令&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">df</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -h</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">df</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -i</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">mount</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> column</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -t</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">findmnt</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">iostat</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -x</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">pidstat</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -d</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> 1</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">filefrag</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -v</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> file</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">stat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> file</span></span></code></pre></div><p>看 writeback:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cat</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> /proc/meminfo</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -E</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;Dirty|Writeback&#39;</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sysctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vm.dirty_ratio</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> vm.dirty_background_ratio</span></span></code></pre></div><blockquote><p><strong>结论</strong>:文件系统的核心不是&quot;能存文件&quot;,而是&quot;在性能、空间、崩溃一致性之间做取舍&quot;。写高可靠存储代码时,<code>write</code>、<code>fsync</code>、<code>rename</code>、目录 <code>fsync</code> 的边界必须非常清楚。</p></blockquote>`,76)])])}const g=a(l,[["render",t]]);export{k as __pageData,g as default};
